// Requires a <BodhvedaProvider recipientID="recipient_123"> higher in the tree.
function Toggle() {
    const { mutate } = useUpdatePreference();
    return (
        <button
            onClick={() =>
                mutate({
                    target: { channel: "posts", topic: "post_id_123", event: "new_comment" },
                    medium: "email",
                    state: { enabled: false },
                })
